/**
 * SMS notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'sms' channel.
 * Formats notification payloads as plain-text SMS messages and delivers
 * them via a configured provider. In-memory transport is used for testing;
 * the transport method can be overridden for production use (Twilio, SNS, etc.).
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** Default sender phone number or short code. */
  fromNumber: string;
  /** Provider name — for logging and diagnostics. */
  provider: string;
  /** Maximum retries on transient failure. */
  maxRetries: number;
  /** Maximum message length (SMS standard: 160 chars). */
  maxLength: number;
}

const defaultSmsConfig: SmsConfig = {
  fromNumber: '+10000000000',
  provider: 'in-memory',
  maxRetries: 3,
  maxLength: 160,
};

export interface SmsMessage {
  from: string;
  to: string;
  body: string;
  type: NotificationType;
  metadata?: Record<string, unknown>;
}

export interface SentSmsRecord {
  message: SmsMessage;
  sentAt: Date;
  attempts: number;
}

/**
 * Format a notification payload into a concise SMS body.
 * SMS messages are kept short; detailed content should go via email.
 */
function formatSmsBody(payload: NotificationPayload): string {
  switch (payload.type) {
    case 'order:confirmation':
      return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;

    case 'order:status-update':
      return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;

    case 'user:welcome':
      return `Welcome to TaskFlow Pro! ${payload.body}`;

    case 'user:profile-update':
      return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;

    default: {
      const _exhaustive: never = payload.type;
      return `TaskFlow Pro: ${payload.body}`;
    }
  }
}

function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSmsRecord[] = [];
  private config: SmsConfig;

  constructor(config: Partial<SmsConfig> = {}) {
    this.config = { ...defaultSmsConfig, ...config };
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    // Validate recipient phone number
    if (!payload.recipient || !isValidPhoneNumber(payload.recipient)) {
      this.logger.error(`Invalid recipient phone number: ${payload.recipient}`);
      return {
        success: false,
        notificationId: '',
        channel: 'sms',
        error: `Invalid recipient phone number: ${payload.recipient}`,
      };
    }

    // Format the SMS message
    const message = this.formatMessage(payload);

    // Attempt delivery with retries
    let lastError: string | undefined;
    for (let attempt = 1; attempt <= this.config.maxRetries; attempt++) {
      try {
        await this.transport(message);

        this.sentMessages.push({
          message,
          sentAt: new Date(),
          attempts: attempt,
        });

        this.logger.info(
          `SMS sent from ${message.from} to ${message.to}: ${payload.type} (attempt ${attempt})`,
        );

        return {
          success: true,
          notificationId: '',
          channel: 'sms',
        };
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `SMS send attempt ${attempt}/${this.config.maxRetries} failed: ${lastError}`,
        );
      }
    }

    this.logger.error(
      `SMS delivery failed after ${this.config.maxRetries} attempts to ${payload.recipient}: ${lastError}`,
    );

    return {
      success: false,
      notificationId: '',
      channel: 'sms',
      error: `Delivery failed after ${this.config.maxRetries} attempts: ${lastError}`,
    };
  }

  /**
   * Format a notification payload into an SMS message structure.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    let body = formatSmsBody(payload);

    // Truncate to max length if needed
    if (body.length > this.config.maxLength) {
      body = body.substring(0, this.config.maxLength - 3) + '...';
    }

    return {
      from: this.config.fromNumber,
      to: payload.recipient,
      body,
      type: payload.type,
      metadata: payload.metadata,
    };
  }

  /**
   * The transport layer. In-memory by default; override for production.
   * Production implementations would call Twilio, AWS SNS, etc.
   */
  protected async transport(_message: SmsMessage): Promise<void> {
    // In-memory transport — no-op. Production implementations would call
    // the SMS provider API.
  }

  /**
   * Get all successfully sent SMS messages (useful for testing).
   */
  getSentMessages(): SentSmsRecord[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages (useful for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<SmsConfig> {
    return { ...this.config };
  }
}

