    });

    it('should include metadata when present', () => {
      const message = adapter.formatMessage(
        makePayload({ metadata: { orderId: 'order-1' } }),
      );

      expect(message.metadata).toEqual({ orderId: 'order-1' });
    });
  });

  describe('retry behavior', () => {
    it('should retry on transport failure and succeed', async () => {
      let callCount = 0;
      class FailOnceAdapter extends SmsAdapter {
        protected async transport(): Promise<void> {
          callCount++;
          if (callCount === 1) {
            throw new Error('Transient SMS gateway error');
          }
        }
      }

      const retryAdapter = new FailOnceAdapter({ maxRetries: 3 });
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(callCount).toBe(2);
      expect(retryAdapter.getSentMessages()[0]!.attempts).toBe(2);
    });

    it('should fail after exhausting retries', async () => {
      class AlwaysFailAdapter extends SmsAdapter {
        protected async transport(): Promise<void> {
          throw new Error('SMS gateway down');
        }
      }

      const failAdapter = new AlwaysFailAdapter({ maxRetries: 2 });
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Delivery failed after 2 attempts');
      expect(result.error).toContain('SMS gateway down');
      expect(failAdapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear all sent messages', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559876543' }));
      expect(adapter.getSentMessages()).toHaveLength(2);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('getConfig', () => {
    it('should return a copy of the config', () => {
      const config = adapter.getConfig();
      expect(config.fromNumber).toBe('+10000000000');
      expect(config.provider).toBe('in-memory');
      expect(config.maxRetries).toBe(3);
      expect(config.maxLength).toBe(160);
    });
  });
